+  if (!value) {
+    return null;
+  }
+
+  return {
+    allowedApprovalPolicies: stringList(value.allowedApprovalPolicies),
+    allowedSandboxModes: stringList(value.allowedSandboxModes),
+    allowedWebSearchModes: stringList(value.allowedWebSearchModes),
