+function pushIssue(
+  issues: OffdexRuntimeReadinessIssue[],
+  issue: OffdexRuntimeReadinessIssue
+) {
+  if (!issues.some((entry) => entry.id === issue.id)) {
+    issues.push(issue);
+  }
